SELECT run_number
FROM flight_runs
ORDER BY run_number;

SELECT COUNT(run_number) AS total_flights
FROM flight_runs
WHERE flight_date = '2023-10-01';

SELECT run_number
FROM flight_runs
ORDER BY flight_date DESC, run_number ASC;

SELECT run_number, total_time_of_launch
FROM flight_runs
ORDER BY total_time_of_launch DESC;

SELECT run_number, flight_date
FROM flight_runs
ORDER BY flight_date DESC;
